  4783 | /// This is called when we find an icmp instruction
  4784 | /// (a seteq/setne with a constant) as the only instruction in a
  4785 | /// block that ends with an uncond branch.  We are looking for a very specific
  4786 | /// pattern that occurs when "A == 1 || A == 2 || A == 3" gets simplified.  In
  4787 | /// this case, we merge the first two "or's of icmp" into a switch, but then the
  4788 | /// default value goes to an uncond block with a seteq in it, we get something
  4789 | /// like:
  4790 | ///
  4791 | ///   switch i8 %A, label %DEFAULT [ i8 1, label %end    i8 2, label %end ]
  4792 | /// DEFAULT:
  4793 | ///   %tmp = icmp eq i8 %A, 92
  4794 | ///   br label %end
  4795 | /// end:
  4796 | ///   ... = phi i1 [ true, %entry ], [ %tmp, %DEFAULT ], [ true, %entry ]
  4797 | ///
  4798 | /// We prefer to split the edge to 'end' so that there is a true/false entry to
  4799 | /// the PHI, merging the third icmp into the switch.
  4800 | bool SimplifyCFGOpt::tryToSimplifyUncondBranchWithICmpInIt(
  4801 |     ICmpInst *ICI, IRBuilder<> &Builder) {
  4802 |   BasicBlock *BB = ICI->getParent();
  4803 | 
  4804 |   // If the block has any PHIs in it or the icmp has multiple uses, it is too
  4805 |   // complex.
  4806 |   if (isa<PHINode>(BB->begin()) || !ICI->hasOneUse())
  4807 |     return false;
  4808 | 
  4809 |   Value *V = ICI->getOperand(0);
  4810 |   ConstantInt *Cst = cast<ConstantInt>(ICI->getOperand(1));
  4811 | 
  4812 |   // The pattern we're looking for is where our only predecessor is a switch on
  4813 |   // 'V' and this block is the default case for the switch.  In this case we can
  4814 |   // fold the compared value into the switch to simplify things.
  4815 |   BasicBlock *Pred = BB->getSinglePredecessor();
  4816 |   if (!Pred || !isa<SwitchInst>(Pred->getTerminator()))
  4817 |     return false;
  4818 | 
  4819 |   SwitchInst *SI = cast<SwitchInst>(Pred->getTerminator());
  4820 |   if (SI->getCondition() != V)
  4821 |     return false;
  4822 | 
  4823 |   // If BB is reachable on a non-default case, then we simply know the value of
  4824 |   // V in this block.  Substitute it and constant fold the icmp instruction
  4825 |   // away.
  4826 |   if (SI->getDefaultDest() != BB) {
  4827 |     ConstantInt *VVal = SI->findCaseDest(BB);
  4828 |     assert(VVal && "Should have a unique destination value");
  4829 |     ICI->setOperand(0, VVal);
  4830 | 
  4831 |     if (Value *V = simplifyInstruction(ICI, {DL, ICI})) {
  4832 |       ICI->replaceAllUsesWith(V);
  4833 |       ICI->eraseFromParent();
  4834 |     }
  4835 |     // BB is now empty, so it is likely to simplify away.
  4836 |     return requestResimplify();
  4837 |   }
  4838 | 
  4839 |   // Ok, the block is reachable from the default dest.  If the constant we're
  4840 |   // comparing exists in one of the other edges, then we can constant fold ICI
  4841 |   // and zap it.
  4842 |   if (SI->findCaseValue(Cst) != SI->case_default()) {
  4843 |     Value *V;
  4844 |     if (ICI->getPredicate() == ICmpInst::ICMP_EQ)
  4845 |       V = ConstantInt::getFalse(BB->getContext());
  4846 |     else
  4847 |       V = ConstantInt::getTrue(BB->getContext());
  4848 | 
  4849 |     ICI->replaceAllUsesWith(V);
  4850 |     ICI->eraseFromParent();

