  Value *LHS = II->getOperand(0);
  Value *RHS = II->getOperand(1);
  if (!LHS->getType()->isIntegerTy() || !RHS->getType()->isIntegerTy())
    return false;

  // Collect mapping from result value to successor block.
  // The switch condition is the intrinsic result.
  assert(SI->getCondition() == II && "switch condition must be the intrinsic");
  DenseMap<BasicBlock *, SmallVector<int8_t, 3>> SuccToValues;
  SmallVector<int8_t, 3> DefaultValues;
  BasicBlock *DefaultSucc = SI->getDefaultDest();

  // Since the result of [us]cmp is in {-1,0,1}, we only care about those values.
  for (auto Case : SI->cases()) {
    ConstantInt *CaseVal = Case.getCaseValue();
    // Only consider cases that are possible results of the intrinsic.
    // The intrinsic returns i8 but could be widened? We'll assume same type.
    // If case value is not -1,0,1, it's impossible, but we ignore.
    int64_t Val = CaseVal->getSExtValue();
    if (Val < -1 || Val > 1)
      continue;
    SuccToValues[Case.getCaseSuccessor()].push_back(static_cast<int8_t>(Val));
  }
  // Values that go to default successor (including impossible values).
  // We'll treat default successor as having the remaining possible values.
  // We'll compute later.

  // Determine the set of possible result values: -1,0,1.
  // For each successor, compute a bitmask of values that map to it.
  // Bit 0: -1, bit 1: 0, bit 2: 1.
  DenseMap<BasicBlock *, uint8_t> SuccMask;
  for (auto &KV : SuccToValues) {
    uint8_t Mask = 0;
    for (int8_t Val : KV.second) {
      if (Val == -1) Mask |= 1 << 0;
      else if (Val == 0) Mask |= 1 << 1;
      else Mask |= 1 << 2;
    }
    SuccMask[KV.first] = Mask;
  }
  // For default successor, we need to compute its mask as complement of all
  // other masks (within possible values). If default successor also has explicit
  // cases (should not happen), we already added them.
  uint8_t ExplicitMask = 0;
  for (auto &KV : SuccMask)
    if (KV.first != DefaultSucc)
      ExplicitMask |= KV.second;
  uint8_t PossibleMask = 0b111; // all three values possible
  uint8_t DefaultMask = PossibleMask & ~ExplicitMask;
  // If default successor is also in SuccMask (had explicit cases), combine.
  if (SuccMask.count(DefaultSucc))
    SuccMask[DefaultSucc] |= DefaultMask;
  else
    SuccMask[DefaultSucc] = DefaultMask;

  // Now we have up to two distinct successors (since switch can have multiple
  // cases mapping to same block). If there are more than two, bail.
  SmallVector<BasicBlock *, 2> DistinctSuccs;
  for (auto &KV : SuccMask)
    DistinctSuccs.push_back(KV.first);
  // Remove duplicates (since same successor may appear multiple times due to
  // multiple cases). Already unique because map keys.
  if (DistinctSuccs.size() > 2)
    return false;

  // Exactly two successors (including default). If there is only one successor,
  // the switch is trivial and should have been folded earlier.
  if (DistinctSuccs.size() != 2)
    return false;

  BasicBlock *SuccA = DistinctSuccs[0];
  BasicBlock *SuccB = DistinctSuccs[1];
  uint8_t MaskA = SuccMask[SuccA];
  uint8_t MaskB = SuccMask[SuccB];
  // Ensure they partition the possible values (MaskA | MaskB == PossibleMask)
  // and (MaskA & MaskB) == 0.
  if ((MaskA | MaskB) != PossibleMask || (MaskA & MaskB) != 0)
    return false;

  // Decide which successor will be the "true" branch (when condition holds).
  // We'll pick SuccA as TrueBB, SuccB as FalseBB.
  // Determine predicate that is true exactly for values in MaskA.
  auto GetPredicate = [&](uint8_t Mask) -> Optional<CmpInst::Predicate> {
    if (IsUnsigned) {
      switch (Mask) {
        case 0b001: return CmpInst::ICMP_ULT;
        case 0b010: return CmpInst::ICMP_EQ;
        case 0b100: return CmpInst::ICMP_UGT;
        case 0b011: return CmpInst::ICMP_ULE;
        case 0b110: return CmpInst::ICMP_UGE;
        case 0b101: return CmpInst::ICMP_NE;
        case 0b111: return None; // always true
        case 0b000: return None; // never true
        default: llvm_unreachable("invalid mask");
      }
    } else {
      switch (Mask) {
        case 0b001: return CmpInst::ICMP_SLT;
        case 0b010: return CmpInst::ICMP_EQ;
        case 0b100: return CmpInst::ICMP_SGT;
        case 0b011: return CmpInst::ICMP_SLE;
        case 0b110: return CmpInst::ICMP_SGE;
        case 0b101: return CmpInst::ICMP_NE;
        case 0b111: return None;
        case 0b000: return None;
        default: llvm_unreachable("invalid mask");
      }
    }
  };
