    // Create unconditional branch to SuccA.
    // We'll let simplifyTerminatorOnSelect handle this case by passing equal
    // TrueBB and FalseBB? Actually we can call simplifyTerminatorOnSelect with
    // condition = constant true? Simpler: just treat as unconditional branch.
    // We'll let the existing switch simplification handle trivial switches?
    // For now bail.
    return false;
  }
  if (!PredB) {
    // Similar.
    return false;
  }
  // PredA is the predicate that is true when intrinsic result in MaskA.
  // That predicate corresponds to LHS,RHS comparison that yields those results.
  // So condition = LHS PredA RHS.
  IRBuilder<> Builder(SI);
  Value *Cond = Builder.CreateICmp(*PredA, LHS, RHS);
  // Determine TrueBB and FalseBB. Since Cond is true exactly when intrinsic
  // result in MaskA, we should branch to SuccA when Cond true, SuccB when false.
  BasicBlock *TrueBB = SuccA;
  BasicBlock *FalseBB = SuccB;
  // Compute branch weights.
  uint32_t TrueWeight = 0, FalseWeight = 0;
  SmallVector<uint64_t, 8> Weights;
  bool HasWeights = hasBranchWeightMD(*SI);
  if (HasWeights) {
    getBranchWeights(SI, Weights);
    if (Weights.size() == 1 + SI->getNumCases()) {
      // Sum weights for each case mapping to TrueBB.
      for (auto Case : SI->cases()) {
        BasicBlock *Succ = Case.getCaseSuccessor();
        if (Succ == TrueBB)
          TrueWeight += (uint32_t)Weights[Case.getSuccessorIndex()];
        else if (Succ == FalseBB)
          FalseWeight += (uint32_t)Weights[Case.getSuccessorIndex()];
        // else other successors (should not happen).
      }
      // Add default weight.
      if (SI->getDefaultDest() == TrueBB)
        TrueWeight += (uint32_t)Weights[0];
      else if (SI->getDefaultDest() == FalseBB)
        FalseWeight += (uint32_t)Weights[0];
    }
  }
