  // So condition = LHS PredA RHS.
  IRBuilder<> Builder(SI);
  Value *Cond = Builder.CreateICmp(*PredA, LHS, RHS);
  BasicBlock *TrueBB = SuccA;
  BasicBlock *FalseBB = SuccB;
